   259→// RoundTrip sets Authorization header for requests.
   260→func (rt *azureADRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
   261→	accessToken, err := rt.tokenProvider.getAccessToken(req.Context())
   262→	if err != nil {
   263→		return nil, err
   264→	}
   265→	bearerAccessToken := "Bearer " + accessToken
   266→	req.Header.Set("Authorization", bearerAccessToken)
   267→
   268→	return rt.next.RoundTrip(req)
   269→}
